/// <summary>
/// SysOperation contract class for updating ETGSPAIN model fields in packing slips.
/// </summary>
[DataContractAttribute]
class ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsContract
{
    //private Set					recordCollection;
    private CustPackingSlipTrans callerBuffer;

    ETGSPAINInventLicensePlate           ETGSPAINInventLicensePlate;
    ETGSPAINSalesCustomerWithdrawalDate  ETGSPAINSalesCustomerWithdrawalDate;
    ETGSPAINCustSalesReference           ETGSPAINCustSalesReference;
    ETGSPAINInventPackingSlipTransitId   ETGSPAINInventPackingSlipTransitId;

}

