/// <summary>
/// Parameter method for setting the <c>callerBuffer</c> variable.
/// </summary>
/// <param name = "_callerBuffer">CustPackingSlipTrans</param>
/// <returns>CustPackingSlipTrans</returns>
[DataMember, SysOperationControlVisibility(false)]
internal CustPackingSlipTrans parmCallerBuffer(CustPackingSlipTrans _callerBuffer = callerBuffer)
{
    callerBuffer = _callerBuffer;
    return callerBuffer;
}

/// <summary>
/// Method to extract values from the <c>callerBuffer</c>.
/// </summary>
public void getInfoFromCallerBuffer()
{
    ETGSPAINCustSalesReference          = callerBuffer.ETGSPAINCustSalesReference;
    ETGSPAINInventLicensePlate          = callerBuffer.ETGSPAINInventLicensePlate;
    ETGSPAINInventPackingSlipTransitId  = callerBuffer.ETGSPAINInventPackingSlipTransitId;
    ETGSPAINSalesCustomerWithdrawalDate = callerBuffer.ETGSPAINSalesCustomerWithdrawalDate;
}

